import math
from typing import Optional


def get_effective_length_le(
    L: float, case: str = "end_span_sagging", L_adjacent: Optional[float] = None
) -> float:
    """Calculate the effective length Le for shear lag assessment.

    Args:
        L (float): Length of the span under consideration.
        case (str): The specific region/case for Le calculation.
            Options:
            'end_span_sagging': Sagging moment area in an end span.
            'internal_span_sagging': Sagging moment area in an internal span.
            'internal_support': Hogging moment area at an internal support.
            'cantilever': Support and end area of a cantilever.
            Defaults to 'end_span_sagging'.
        L_adjacent (float, optional): Length of the adjacent span.
            Required only for 'internal_support' case.

    Returns:
        float: Effective length Le.

    Reference:
        EN 1993-1-5:2006, 3.2.1(2) and Figure 3.1.
    """
    if case == "end_span_sagging":
        # Le = 0.85 * L1
        return 0.85 * L

    if case == "internal_span_sagging":
        # Le = 0.70 * L2
        return 0.70 * L

    if case == "internal_support":
        if L_adjacent is None:
            raise ValueError("L_adjacent is required for internal_support case.")
        # Le = 0.25 * (L1 + L2)
        return 0.25 * (L + L_adjacent)

    if case == "cantilever":
        # Le = 2 * L3
        return 2.0 * L

    # Default fallback: Le is the distance between points of zero moment
    return L


def check_span_consistency(L1: float, L2: float) -> bool:
    """Check if adjacent spans satisfy the 50% difference rule for using Figure 3.1.

    Args:
        L1 (float): Length of the first span.
        L2 (float): Length of the second span.

    Returns:
        bool: True if spans are consistent for Figure 3.1, False otherwise.

    Reference:
        EN 1993-1-5:2006, 3.2.1(2).
    """
    # Spans must not differ more than 50%
    ratio = L1 / L2 if L2 > 0 else 0
    return 0.5 <= ratio <= 1.5


def check_neglect_shear_lag(b0: float, Le: float) -> bool:
    """Check if shear lag in flanges may be neglected.

    Args:
        b0 (float): The flange outstand or half the width of an internal element.
        Le (float): The length between points of zero bending moment.

    Returns:
        bool: True if shear lag may be neglected, False otherwise.

    Reference:
        EN 1993-1-5:2006, 3.1(1)
    """
    return b0 < Le / 50


def get_alpha_0(Asl: float, b0: float, t: float) -> float:
    """Calculate the stiffening factor alpha_0.

    Args:
        Asl (float): Area of all longitudinal stiffeners within the width b0.
        b0 (float): The flange outstand or half the width of an internal element.
        t (float): Thickness of the plate.

    Returns:
        float: Stiffening factor alpha_0.

    Reference:
        EN 1993-1-5:2006, Table 3.1
    """
    return math.sqrt(1 + Asl / (b0 * t))


def get_kappa(alpha_0: float, b0: float, Le: float) -> float:
    """Calculate the parameter kappa for shear lag assessment.

    Args:
        alpha_0 (float): Stiffening factor.
        b0 (float): The flange outstand or half the width of an internal element.
        Le (float): The length between points of zero bending moment.

    Returns:
        float: Parameter kappa.

    Reference:
        EN 1993-1-5:2006, Table 3.1
    """
    return (alpha_0 * b0) / Le


def get_beta_factor(kappa: float, case: str = "sagging") -> float:
    """Calculate the effective width factor beta for elastic shear lag.

    Args:
        kappa (float): Parameter kappa calculated according to Table 3.1.
        case (str): The specific design case.
            Options: 'sagging', 'hogging', 'cantilever', 'end_support'.
            Defaults to 'sagging (M+)'.

    Returns:
        float: Effective width factor beta.

    Reference:
        EN 1993-1-5:2006, Table 3.1
    """
    # Base calculation for beta_1 (sagging) and beta_2 (hogging)
    # according to the kappa ranges in Table 3.1
    if kappa <= 0.02:
        beta_1 = 1.0
        beta_2 = 1.0
    elif 0.02 < kappa <= 0.70:
        beta_1 = 1 / (1 + 6.4 * (kappa**2))
        beta_2 = 1 / (1 + 6.0 * (kappa - 1 / (2500 * kappa)) + 1.6 * (kappa**2))
    else:  # kappa > 0.70
        beta_1 = 1 / (5.9 * kappa)
        beta_2 = 1 / (8.6 * kappa)

    # Specific logic for each case based on Table 3.1
    if case == "sagging":
        return beta_1

    if case == "hogging":
        return beta_2

    if case == "cantilever":
        # Table 3.1: "Cantilever beta = beta_2 at support and at the end"
        return beta_2

    if case == "end_support":
        # Table 3.1: "end support beta_0 = (0.55 + 0.025 / kappa) * beta_1, but beta_0 < beta_1"
        beta_0 = (0.55 + 0.025 / kappa) * beta_1
        return min(beta_0, beta_1)

    return 1.0


def get_beff(beta: float, b0: float) -> float:
    """Calculate the effective width for shear lag.

    Args:
        beta (float): Effective width factor for elastic shear lag.
        b0 (float): The flange outstand or half the width of an internal element.

    Returns:
        float: Effective width beff.

    Reference:
        EN 1993-1-5:2006, Equation (3.1)
    """
    return beta * b0


def get_patch_load_stress(FEd: float, beff: float, tw: float, ast1: float) -> float:
    """Calculate the elastic stress due to patch loading (in-plane forces).

    Args:
        FEd (float): Design transverse force.
        beff (float): Effective width for the patch load.
        tw (float): Web thickness.
        ast1 (float): Gross cross-sectional area of loaded stiffeners divided by length se.

    Returns:
        float: Transverse stress sigma_z,Ed.

    Reference:
        EN 1993-1-5:2006, Equation (3.2)
    """
    return FEd / (beff * (tw + ast1))


def get_patch_load_stress_detailed(
    FEd: float, ss: float, tf: float, tw: float, z: float, Ast: float, sst: float
) -> float:
    """Calculate the elastic stress due to patch loading with internal parameter derivation.

    Args:
        FEd (float): Design transverse force.
        ss (float): Length of stiff bearing.
        tf (float): Flange thickness.
        tw (float): Web thickness.
        z (float): Distance from the flange-web junction to the section of study.
        Ast (float): Gross cross-sectional area of a single transverse stiffener.
        sst (float): Spacing of the transverse stiffeners.

    Returns:
        float: Transverse stress sigma_z,Ed.

    Reference:
        EN 1993-1-5:2006, 3.2.3 and Equation (3.2).
    """
    # 1. Calculate the length of the stiff bearing se
    # Reference: EN 1993-1-5:2006, 3.2.3(1) formula for se
    se = ss + 2 * tf

    # 2. Determine ast,1 (smeared area of stiffeners)
    # Note: Valid when sst/se <= 0.5; otherwise stiffeners are neglected.
    # Reference: EN 1993-1-5:2006, 3.2.3(1) NOTE
    if sst / se <= 0.5:
        # ast,1 is the area of a stiffener smeared over the spacing sst
        ast1 = Ast / sst
    else:
        ast1 = 0.0

    # 3. Calculate the parameter n
    # Reference: EN 1993-1-5:2006, 3.2.3(1) formula for n
    n = 0.636 + 0.878 * math.sqrt(ast1 / tw)

    # 4. Calculate the effective width beff at distance z
    # Reference: EN 1993-1-5:2006, 3.2.3(1) formula for beff
    beff = se * math.sqrt(1 + ((z / se) ** 2) * n)

    # 5. Calculate the final transverse stress sigma_z,Ed
    # Reference: EN 1993-1-5:2006, Equation (3.2)
    sigma_z_Ed = FEd / (beff * (tw + ast1))

    return sigma_z_Ed


def get_shear_lag_stress(y: float, sigma_1: float, beta: float, b0: float) -> float:
    """Calculate the longitudinal stress at a distance y from the web-flange junction.

    Args:
        y (float): Distance from the junction (0 <= y <= b0).
        sigma_1 (float): Stress calculated with the effective width beff.
        beta (float): Effective width factor.
        b0 (float): The flange outstand or half the width of an internal element.

    Returns:
        float: Longitudinal stress sigma(y).

    Reference:
        EN 1993-1-5:2006, Figure 3.3
    """
    if beta > 0.20:
        # Case for beta > 0.20
        sigma_2 = 1.25 * (beta - 0.20) * sigma_1
        return sigma_2 + (sigma_1 - sigma_2) * (1 - y / b0) ** 2
    else:
        # Case for beta <= 0.20
        # b1 is a hypothetical width defined in Figure 3.3
        b1 = 5 * beta * b0
        if y <= b1:
            return sigma_1 * (1 - y / b1) ** 2
        else:
            return 0.0


def get_alpha_0_star(Ac_eff: float, b0: float, tf: float) -> float:
    """Calculate the modified stiffening factor alpha_0_star for ULS.

    Args:
        Ac_eff (float): Effective p area of the compression flange (due to buckling).
        b0 (float): The flange outstand or half the width of an internal element.
        tf (float): Flange thickness.

    Returns:
        float: Modified stiffening factor alpha_0_star.

    Reference:
        EN 1993-1-5:2006, Equation (3.4)
    """
    return math.sqrt(Ac_eff / (b0 * tf))


def get_aeff_uls_combined(Ac_eff: float, beta_ult: float) -> float:
    """Calculate the combined effective area (buckling + shear lag) for ULS (Note 2).

    Args:
        Ac_eff (float): Effective area due to plate buckling (from Section 4).
        beta_ult (float): Effective s width factor for ULS using alpha_0_star.

    Returns:
        float: Combined effective area Aeff.

    Reference:
        EN 1993-1-5:2006, Equation (3.3)
    """
    return beta_ult * Ac_eff


def get_aeff_uls_plastic(Ac_eff: float, beta: float, kappa: float) -> float:
    """Calculate effective area allowing for limited plastic strains (Note 3).

    Args:
        Ac_eff (float): Effective area due to plate buckling (from Section 4).
        beta (float): Elastic effective s factor from Table 3.1.
        kappa (float): Parameter kappa from Table 3.1.

    Returns:
        float: Combined effective area Aeff.

    Reference:
        EN 1993-1-5:2006, Equation (3.5)
    """
    # Note: For tension flanges, Ac_eff should be replaced by the gross area.
    return Ac_eff * (beta**kappa)
